import React from 'react';
import {Grid, Row, Col,Jumbotron, Navbar, NavDropdown, NavItem, Nav, MenuItem} from 'react-bootstrap'

class App extends React.Component {
   render() {
      return (
         <div>
            <Navbar inverse collapseOnSelect fixedTop>
                <Navbar.Header>
                    <Navbar.Brand>
                        <a href="#brand">欧</a>
                    </Navbar.Brand>
                    <Navbar.Toggle />
                </Navbar.Header>
                <Navbar.Collapse>
                    <Nav>
                        <NavItem eventKey={1} href="#">
                            介绍
                        </NavItem>
                        <NavItem eventKey={2} href="#">
                            联系方式
                        </NavItem>
                        <NavDropdown eventKey={3} title="测评" id="basic-nav-dropdown">
                            <MenuItem eventKey={3.1}>结界合成初级</MenuItem>
                            <MenuItem eventKey={3.2}>结界合成中级</MenuItem>
                            <MenuItem eventKey={3.3}>结界合成高级</MenuItem>
                            <MenuItem divider />
                            <MenuItem eventKey={3.3}>证书</MenuItem>
                        </NavDropdown>
                    </Nav>
                    <Nav pullRight>
                        <NavItem eventKey={1} href="#">
                            举报
                        </NavItem>
                        <NavItem eventKey={2} href="#">
                            投诉
                        </NavItem>
                    </Nav>
                </Navbar.Collapse>
            </Navbar>
            <header className="masthead text-warning text-center">
                <Jumbotron className="jumbotron-fluid">
                    <img src="Images/susu.jpg" className="img-responsive mb-5 d-block mx-auto"/>
                    <h1>念着倒皇欧</h1>
                    <hr className="star-light"></hr>
                    <h2>欢迎来到欧皇的世界</h2>
                </Jumbotron>
            </header>
         </div>
      );
   }
}
export default App;